mapper.select:
SELECT m.*, c.course_name, f.file_name as file_name, f.file_path FROM edu_teaching_material m LEFT JOIN edu_course c ON m.course_id = c.id LEFT JOIN sys_file_info f ON m.file_id = f.id
AND m.audit_status = #{auditStatus}
AND m.material_type = #{materialType}
AND m.course_id = #{courseId}
AND m.title LIKE CONCAT('%', #{title}, '%')
AND m.teacher_id = #{teacherId}
ORDER BY m.create_time DESC

