title = #{title}, material_type = #{materialType}, course_id = #{courseId}, file_id = #{fileId}, audit_status = #{auditStatus}, auditor_id = #{auditorId}, auditor_name = #{auditorName}, audit_time = #{auditTime}, audit_remark = #{auditRemark},
